SELECT u.user_id, u.username, u.email
FROM users u
JOIN user_blocklist bl ON u.user_id = bl.blocked_user_id;

SELECT DISTINCT users.user_id, users.username
FROM users
INNER JOIN posts ON users.user_id = posts.user_id;

SELECT AVG(post_count)
FROM (
  SELECT user_id, COUNT(post_id) as post_count
  FROM posts
  GROUP BY user_id
);

SELECT AVG(post_count) AS average_posts_per_user
FROM (
  SELECT user_id, COUNT(*) AS post_count
  FROM posts
  GROUP BY user_id
) AS user_post_counts;

SELECT post_id, created_at, likes,
       SUM(likes) OVER (ORDER BY created_at) AS running_total
FROM posts;

SELECT u.username, u.email, ur.role_name
FROM users u
JOIN user_roles ur ON u.role_id = ur.role_id
WHERE u.user_id NOT IN (
    SELECT c.user_id FROM comments c
)
AND u.user_id NOT IN (
    SELECT ub.user_id FROM user_blocklist ub WHERE ub.user_id = ub.blocked_user_id
)
AND u.user_id NOT IN (
    SELECT mr.user_id FROM moderation_reports mr
)
AND u.is_active = 1;
